# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")

# Environment variables
RESULTS_BUCKET = os.environ.get("RESULTS_BUCKET", "my-app-results")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SUPPORTED_IMAGE_TYPES = {".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".tiff"}
MAX_IMAGE_SIZE_BYTES = 50 * 1024 * 1024  # 50 MB


class ImageProcessingError(Exception):
    """Custom exception for image processing failures."""
    pass


class UnsupportedImageTypeError(ImageProcessingError):
    """Raised when the uploaded file is not a supported image type."""
    pass


class ImageTooLargeError(ImageProcessingError):
    """Raised when the uploaded image exceeds the size limit."""
    pass


def validate_image_key(key):
    """Validate that the S3 object key refers to a supported image type."""
    key_lower = key.lower()
    extension = os.path.splitext(key_lower)[1]
    if extension not in SUPPORTED_IMAGE_TYPES:
        raise UnsupportedImageTypeError(
            f"Unsupported image type '{extension}' for key '{key}'. "
            f"Supported types: {SUPPORTED_IMAGE_TYPES}"
        )
    return extension


def get_image_from_s3(bucket, key):
    """Download an image from S3 and return its bytes and metadata."""
    logger.info(f"Fetching image from s3://{bucket}/{key}")

    try:
        head_response = s3_client.head_object(Bucket=bucket, Key=key)
        content_length = head_response.get("ContentLength", 0)

        if content_length > MAX_IMAGE_SIZE_BYTES:
            raise ImageTooLargeError(
                f"Image size {content_length} bytes exceeds maximum "
                f"allowed size of {MAX_IMAGE_SIZE_BYTES} bytes."
            )

        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response["Body"].read()

        metadata = {
            "content_type": response.get("ContentType", "unknown"),
            "content_length": content_length,
            "last_modified": str(response.get("LastModified", "")),
            "etag": response.get("ETag", ""),
            "original_metadata": response.get("Metadata", {}),
        }

        logger.info(
            f"Successfully fetched image: {content_length} bytes, "
            f"type: {metadata['content_type']}"
        )
        return image_data, metadata

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "NoSuchKey":
            logger.error(f"Image not found: s3://{bucket}/{key}")
            raise ImageProcessingError(f"Image not found: s3://{bucket}/{key}") from e
        elif error_code == "AccessDenied":
            logger.error(f"Access denied for s3://{bucket}/{key}")
            raise ImageProcessingError(
                f"Access denied reading s3://{bucket}/{key}. Check IAM permissions."
            ) from e
        else:
            logger.error(f"S3 error fetching image: {e}")
            raise


def process_image(image_data, metadata, file_extension):
    """
    Process the image and return results.

    This is the core processing function. For the MVP, it extracts basic
    image information. Extend this function to add:
    - Thumbnail generation (using Pillow)
    - Image classification (using AWS Rekognition)
    - EXIF data extraction
    - Content moderation
    - Resizing / format conversion
    """
    logger.info("Processing image...")

    processing_id = str(uuid.uuid4())
    timestamp = datetime.utcnow().isoformat() + "Z"

    # Basic image analysis (MVP)
    results = {
        "processing_id": processing_id,
        "timestamp": timestamp,
        "status": "completed",
        "original_size_bytes": len(image_data),
        "content_type": metadata["content_type"],
        "file_extension": file_extension,
        "original_metadata": metadata["original_metadata"],
        "analysis": {
            "file_size_category": _categorize_file_size(len(image_data)),
        },
    }

    # Attempt to extract image dimensions if Pillow is available
    try:
        from PIL import Image
        import io

        with Image.open(io.BytesIO(image_data)) as img:
            width, height = img.size
            results["analysis"]["width"] = width
            results["analysis"]["height"] = height
            results["analysis"]["aspect_ratio"] = round(width / height, 4) if height > 0 else None
            results["analysis"]["mode"] = img.mode
            results["analysis"]["format"] = img.format

            # Generate thumbnail
            thumbnail_data = _generate_thumbnail(img)
            results["_thumbnail_data"] = thumbnail_data

            logger.info(f"Image dimensions: {width}x{height}, mode: {img.mode}")

    except ImportError:
        logger.warning(
            "Pillow not available in Lambda environment. "
            "Add Pillow as a Lambda layer for image dimension analysis. "
            "Skipping dimension extraction."
        )
    except Exception as e:
        logger.warning(f"Could not extract image dimensions: {e}")
        results["analysis"]["dimension_extraction_error"] = str(e)

    logger.info(f"Processing complete. ID: {processing_id}")
    return results


def _categorize_file_size(size_bytes):
    """Categorize file size into human-readable buckets."""
    if size_bytes < 100 * 1024:
        return "small"
    elif size_bytes < 1 * 1024 * 1024:
        return "medium"
    elif size_bytes < 10 * 1024 * 1024:
        return "large"
    else:
        return "very_large"


def _generate_thumbnail(pil_image, max_size=(200, 200)):
    """Generate a thumbnail from a PIL Image object."""
    import io

    thumbnail = pil_image.copy()
    thumbnail.thumbnail(max_size)

    buffer = io.BytesIO()
    output_format = pil_image.format if pil_image.format in ("JPEG", "PNG", "WEBP") else "JPEG"
    if output_format == "JPEG" and thumbnail.mode in ("RGBA", "P"):
        thumbnail = thumbnail.convert("RGB")
    thumbnail.save(buffer, format=output_format, quality=85)
    buffer.seek(0)
    return buffer.read()


def save_results_to_s3(results, source_bucket, source_key):
    """Save processing results as JSON to the results S3 bucket."""
    processing_id = results["processing_id"]

    # Remove binary data before JSON serialization
    results_for_json = {k: v for k, v in results.items() if not k.startswith("_")}

    # Build the result key mirroring the source structure
    base_key = os.path.splitext(source_key)[0]
    result_key = f"results/{base_key}/{processing_id}.json"

    logger.info(f"Saving results to s3://{RESULTS_BUCKET}/{result_key}")

    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=result_key,
            Body=json.dumps(results_for_json, indent=2, default=str),
            ContentType="application/json",
            Metadata={
                "source-bucket": source_bucket,
                "source-key": source_key,
                "processing-id": processing_id,
            },
        )
        logger.info(f"Results saved successfully: {result_key}")

    except ClientError as e:
        logger.error(f"Failed to save results to S3: {e}")
        raise ImageProcessingError(f"Failed to save results: {e}") from e

    # Save thumbnail if available
    thumbnail_data = results.get("_thumbnail_data")
    if thumbnail_data:
        thumbnail_key = f"thumbnails/{base_key}_thumb.jpg"
        try:
            s3_client.put_object(
                Bucket=RESULTS_BUCKET,
                Key=thumbnail_key,
                Body=thumbnail_data,
                ContentType="image/jpeg",
                Metadata={
                    "source-bucket": source_bucket,
                    "source-key": source_key,
                    "processing-id": processing_id,
                },
            )
            logger.info(f"Thumbnail saved: {thumbnail_key}")
            results_for_json["thumbnail_key"] = thumbnail_key
        except ClientError as e:
            logger.warning(f"Failed to save thumbnail: {e}")

    return result_key, results_for_json


def send_notification(results, source_bucket, source_key, result_key):
    """Send an SNS notification about the processing result."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured. Skipping notification.")
        return

    processing_id = results.get("processing_id", "unknown")
    status = results.get("status", "unknown")

    subject = f"Image Processing {status.capitalize()}: {os.path.basename(source_key)}"

    message = {
        "default": json.dumps({
            "processing_id": processing_id,
            "status": status,
            "source": f"s3://{source_bucket}/{source_key}",
            "results_location": f"s3://{RESULTS_BUCKET}/{result_key}",
            "timestamp": results.get("timestamp", ""),
            "summary": {
                "original_size": results.get("original_size_bytes"),
                "dimensions": f"{results.get('analysis', {}).get('width', '?')}x"
                              f"{results.get('analysis', {}).get('height', '?')}",
            },
        }, default=str),
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject max 100 chars
            Message=json.dumps(message),
            MessageStructure="json",
            MessageAttributes={
                "status": {
                    "DataType": "String",
                    "StringValue": status,
                },
                "processing_id": {
                    "DataType": "String",
                    "StringValue": processing_id,
                },
            },
        )
        logger.info(f"SNS notification sent for processing ID: {processing_id}")

    except ClientError as e:
        logger.error(f"Failed to send SNS notification: {e}")
        # Don't raise - notification failure shouldn't fail the whole process


def send_error_notification(source_bucket, source_key, error_message):
    """Send an SNS notification about a processing failure."""
    if not SNS_TOPIC_ARN:
        return

    subject = f"Image Processing FAILED: {os.path.basename(source_key)}"

    message = {
        "default": json.dumps({
            "status": "failed",
            "source": f"s3://{source_bucket}/{source_key}",
            "error": error_message,
            "timestamp": datetime.utcnow().isoformat() + "Z",
        }),
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message),
            MessageStructure="json",
            MessageAttributes={
                "status": {
                    "DataType": "String",
                    "StringValue": "failed",
                },
            },
        )
    except ClientError:
        logger.error("Failed to send error notification via SNS")


